// Filtra tarefas onde Data.date.end existe e é <= hoje (vencidas ou vencendo hoje)
const today = new Date($today);
today.setHours(0, 0, 0, 0);

const items = $input.all();
const filtered = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const data = item.json?.properties?.Data;

  if (!data?.date?.end) continue;

  const endDate = new Date(data.date.end);
  endDate.setHours(0, 0, 0, 0);

  if (endDate <= today) {
    filtered.push({ json: item.json, pairedItem: { item: i } });
  }
}

return filtered;

